INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("REPORTING_PERIOD", "TIME", "TUPLE", "Specific time span covered by the information reported, typically expressed as a tuple <start time, end time>. Example units of measurment: seconds, hours, days, months or a combination thereof", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TIME_DURATION", "TIME", "LIST_OF_TERMS", "Terms indicating duration of something (E.g., annual, monthly, etc.).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GEOLOCATION", "LOCATION", "LIST_OF_NUMBERS", "Geographical location, typically expressed as <latitude, longitude> or as a bounding box, i.e., list of <latitude, longitude> points.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LIST_OF_PLACES", "LOCATION", "LIST_OF_TERMS", "A list of geographical locations expressed as a list of names (e.g., countries)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LEGAL_FORM", "LEGAL", "SINGLE_TERM", "Type of business entity (for example general partnership, chartered company, public limited company, subsidiary company, holding company, etc.).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("STAKEHOLDER", "ORGANIZATIONAL", "NUMBER", "Entity or individual that can reasonably be expected to be significantly affected by the reporting organization’s activities, products and services, or whose actions can reasonably be expected to affect the ability of the organization to successfully implement its strategies and achieve its objectives", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOPIC", "ORGANIZATIONAL", "NUMBER", "Economic, environmental or social subject. Note 1: In the GRI Standards, topics are grouped according to the three dimensions of sustainable development: economic, environmental and social. Note 2: To prepare a report in accordance with the GRI Standards, an organization is required to report on its material topics.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("IMPACT", "ORGANIZATIONAL", "LIST_OF_TERMS", "In the GRI Standards, unless otherwise stated, ‘impact’ refers to the effect an organization has on theeconomy, the environment, and/or society, which in turn can indicate its contribution (positive or negative) to sustainable development. Note 1: In the GRI Standards, the term ‘impact’ can refer to positive, negative, actual, potential, direct, indirect, short-term, long-term, intended, or unintended impacts. Note 2: Impacts on the economy, environment, and/or society can also be related to consequences for the organization itself. For example, an impact on the economy, environment, and/or society can lead to consequences for the organization’s business model, reputation, or ability to achieve its objectives.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOPIC_BOUNDARY", "ORGANIZATIONAL", "DOCUMENT", "Description of where the impacts occur for a material topic, and the organization’s involvement with those impacts.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("DUE_DILIGENCE", "ORGANIZATIONAL", "DOCUMENT", "In the context of the GRI Standards, ‘due diligence’ refers to a process to identify, prevent, mitigate and account for how an organization addresses its actual and potential negative impacts.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("MATERIAL_TOPIC", "ORGANIZATIONAL", "SINGLE_TERM", "Topic that reflects a reporting organization’s significant economic, environmental and social impacts; or that substantively influences the assessments and decisions of stakeholders", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PRODUCT", "ORGANIZATIONAL", "SINGLE_TERM", "Article or substance that is offered for sale or is part of a service delivered by an organization.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SERVICE", "ORGANIZATIONAL", "SINGLE_TERM", "Action of an organization to meet a demand or need", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PRODUCT_OR_SERVICE_CATEGORY", "ORGANIZATIONAL", "LIST_OF_TERMS", "Group of related products or services sharing a common, managed set of features that satisfy the specific needs of a selected market", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("COLLECTIVE_BARGAINING", "ORGANIZATIONAL, HUMAN_RESOURCES", "NUMBER", "All negotiations which take place between one or more employers or employers' organizations, on the one hand, and one or more workers' organizations (trade unions), on the other, for determining working conditions and terms of employment or for regulating relations between employers and workers", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PRECAUTIONARY_APPROACH", "ENVIRONMENTAL", "DOCUMENT", "The precautionary approach was introduced by the United Nations in Principle 15 of ‘The Rio Declaration on Environment and Development’. It states: ‘In order to protect the environment, the precautionary approach shall be widely applied by States according to their capabilities. Where there are threats of serious or irreversible damage, lack of full scientific certainty shall not be used as a reason for postponing cost-effective measures to prevent environmental degradation.’ Applying the Precautionary Principle can help an organization to reduce or to avoid negative impacts on the environment.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SECTOR", "SOCIETAL", "LIST_OF_TERMS", "One or more sectors. A sector is asubdivision of an economy, society or sphere of activity, defined on the basis of some common characteristic Note: Sector types can include classifications such as the public or private sector, and industry specific categories such as the education, technology, or financial sectors.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GENDER", "SOCIETAL", "LIST_OF_TERMS", "Range of characteristics pertaining to, and differentiating between femininity and masculinity. Depending on the context, this may include sex-based social structures (i.e. gender roles) and gender identity.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("UNDER-REPRESENTED_SOCIAL_GROUP", "SOCIETAL", "DOCUMENT", "Population that, relative to its numbers in a given society, has less opportunity to express its economic, social, or political needs and views Note: Specific groups included under this definition are not uniform for every organization. An organization identifies relevant groups based on its operating context.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LOCAL_COMMUNITY", "SOCIETAL", "LIST_OF_TERMS", "Persons or groups of persons living and/or working in any areas that are economically, socially or environmentally impacted (positively or negatively) by an organization’s operations Note: The local community can range from persons living adjacent to an organization’s operations, to those living at a distance who are still likely to be impacted by these operations.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CONFLICT_OF_INTEREST", "SOCIETAL", "DOCUMENT", "Situation where an individual is confronted with choosing between the requirements of his or her function and his or her own private interests.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EMPLOYEE", "HUMAN_RESOURCES", "NUMBER", "One or more employees, i.e., person or people working for an organization. Expressed in a natural number (i.e., positive integer).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EMPLOYEE_CATEGORY", "HUMAN_RESOURCES", "LIST_OF_TERMS", "Breakdown of employees by level (such as senior management, middle management) and function (such as technical, administrative, production).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORKER", "HUMAN_RESOURCES", "NUMBER", "One or more person/people that perform(s) work. The term ‘workers’ includes, but is not limited to, employees. Further examples of workers include interns, apprentices, self-employed persons, and persons working for organizations other than the reporting organization, e.g., for suppliers", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CLAWBACK", "HUMAN_RESOURCES, FINANCIAL", "NUMBER", "Repayment of previously received compensation required to be made by an executive to his or her employer in the event certain conditions of employment or goals are not met. Expressed in a form of currency (e.g., amount of US Dollars, Swedish Crowns, etc.).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TERMINATION_PAYMENT", "HUMAN_RESOURCES, FINANCIAL", "NUMBER", "All payments made and benefits given to a departing executive or member of the highest governance body whose appointment is terminated. Expressed in a form of currency (e.g., amount of US Dollars, Swedish Crowns, etc.).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ANNUAL_TOTAL_COMPENSATION", "HUMAN_RESOURCES, FINANCIAL", "NUMBER", "Compensation provided over the course of a year. Expressed in a currency equivalent (e.g., US Dollars or Swedish Crowns). Annual total compensation can include compensation such as salary, bonus, stock awards, option awards, non-equity incentive plan compensation, change in pension value and nonqualified deferred compensation earnings, and all other compensation.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EMPLOYMENT_CONTRACT", "HUMAN_RESOURCES", "DOCUMENT", "Contract as recognized under national law or practice that can be written, verbal, or implicit (that is, when all the characteristics of employment are present but without a written or witnessed verbal contract) Indefinite or permanent contract: A permanent employment contract is a contract with an employee, for fulltime or part-time work, for an indeterminate period. Fixed term or temporary contract: A fixed term employment contract is an employment contract as defined above that ends when a specific time period expires, or when a specific task that has a time estimate attached is completed. A temporary employment contract is of limited duration, and is terminated by a specific event, including the end of a project or work phase or return of replaced employees.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EMPLOYMENT_TYPE", "HUMAN_RESOURCES", "ONE_OF_TERMS", "Full-time: A ‘full-time employee’ is an employee whose working hours per week, month, or year are defined according to national legislation and practice regarding working time (such as national legislation which defines that ‘full-time’ means a minimum of nine months per year and a minimum of 30 hours per week). Part-time: A ‘part-time employee’ is an employee whose working hours per week, month, or year are less than ‘full-time’ as defined above.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SUPPLY_CHAIN", "LOGISTICS", "LIST_OF_TERMS", "Sequence of activities or parties that provides products or services to an organization.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LOCAL_SUPPLIER", "LOGISTICS", "SINGLE_TERM", "organization or person that provides a product or service to the reporting organization, and that is based in the same geographic market as the reporting organization (that is, no transnational payments are made to a local supplier)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SUPPLIER", "LOGISTICS", "SINGLE_TERM", "Organization or person that provides a product or service used in the supply chain of the reporting organization.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SUSTAINABILITY", "FINANCIAL, ENVIRONMENTAL, SOCIETAL", "DOCUMENT", "Development that meets the needs of the present without compromising the ability of future generations to meet their own needs Note 1: Sustainable development encompasses three dimensions: economic, environmental and social. Note 2: Sustainable development refers to broader environmental and societal interests, rather than to the interests of specific organizations. Note 3: In the GRI Standards, the terms ‘sustainability’ and ‘sustainable development’ are used interchangeably.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GOVERNANCE_BODY", "ORGANIZATIONAL", "DOCUMENT", "Committee or board responsible for the strategic guidance of the organization, the effective monitoring of management, and the accountability of management to the broader organization and its stakeholders.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("REPORTING_PRINCIPLE", "ORGANIZATIONAL", "DOCUMENT", "Concept that describes the outcomes a report is expected to achieve, and that guides decisions made throughout the reporting process around report content or quality.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("VALUE_CHAIN", "ORGANIZATIONAL", "DOCUMENT", "An organization’s value chain encompasses the activities that convert input into output by adding value. It includes entities with which the organization has a direct or indirect business relationship and which either (a) supply products or services that contribute to the organization’s own products or services, or (b) receive products or services from the organization.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRIEVANCE_MECHANISM", "ORGANIZATIONAL", "DOCUMENT", "System consisting of procedures, roles and rules for receiving complaints and providing remedy. Effective grievance mechanisms are expected to be legitimate, accessible, predictable, equitable, transparent, rights-compatible, and a source of continuous learning. For operational-level mechanisms to be effective, they are expected to be based on engagement and dialogue. For a description of each of these criteria, see Guiding Principle 31 in the United Nations (UN), ‘Guiding Principles on Business and Human Rights, Implementing the United Nations “Protect, Respect and Remedy” Framework’, 2011.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("DEFINED_BENEFIT_PLAN", "HUMAN_RESOURCES", "DOCUMENT", "Post-employment benefit plan other than a defined contribution plan.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("DEFINED_CONTRIBUTION_PLAN", "HUMAN_RESOURCES", "DOCUMENT", "Post-employment benefit plan under which an entity pays fixed contributions into a separate entity (a fund) and will have no legal or constructive obligation to pay further contributions if the fund does not hold sufficient assets to pay all employee benefits relating to employee service in the current and prior periods.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("FULL_COVERAGE", "HUMAN_RESOURCES", "DOCUMENT", "Plan assets that meet or exceed plan obligations.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("FINANCIAL_ASSISTANCE", "ORGANIZATIONAL, FINANCIAL", "LIST_OF_NUMBERS", "Direct or indirect financial benefits that do not represent a transaction of goods and services, but which are an incentive or compensation for actions taken, the cost of an asset, or expenses incurred", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("NET_SALES", "FINANCIAL", "NUMBER", "How much of a product and/or service an organization has sold, expressed in a currency equivalent (e.g., US Dollars or Swedish Crowns)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("NET_REVENUES", "FINANCIAL", "NUMBER", "Total amount of income generated by the sale of goods or services related to the company's primary operations. Expressed in a currency equivalent (e.g., US Dollars or Swedish Crowns)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CAPITALIZATION", "FINANCIAL", "NUMBER", "Accounting method in which a cost is included in the value of an asset and expensed over the useful life of that asset, rather than being expensed in the period the cost was originally incurred.  Expressed in a currency equivalent (e.g., US Dollars or Swedish Crowns)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TABLE_1-GRI-101", "DOC_RESOURCE", "NaN",  "Refer to table 1 at page 22 of document <a href=\"GRI 101\">https://www.globalreporting.org/standards/media/1036/gri-101-foundation-2016.pdf</a>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TABLE_2-GRI-101", "DOC_RESOURCE", "NaN",  "Refer to table 2 at page 24 of document <a href=\"GRI 101\">https://www.globalreporting.org/standards/media/1036/gri-101-foundation-2016.pdf</a>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("MAIL_GLOBALREPORTING", "DOC_RESOURCE", "NaN",  "mailto:standards@globalreporting.org", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("URL_GLOBALREPORTING", "DOC_RESOURCE", "NaN",  "<a href=\"www.globalreporting.org/standards\">GlobalReporting Standards</a>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LOCAL_MINIMUM_WAGE", "HUMAN_RESOURCES, FINANCIAL", "NUMBER",  "Minimum compensation for employment per hour, or other unit of time, allowed under law, expressed in a form of currency (e.g., US Dollars or Swedish Crowns).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ENTRY_LEVEL_WAGE", "HUMAN_RESOURCES, FINANCIAL", "NaN",  "Full-time wage in the lowest employment category, expressed in a form of currency (e.g., US Dollars or Swedish Crowns).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("INFRASTRUCTURE", "ORGANIZATIONAL, SOCIETAL", "NaN",  "Facilities built primarily to provide a public service or good rather than a commercial purpose, and from which an organization does not seek to gain direct economic benefit.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CORRUPTION", "ORGANIZATIONAL, SOCIETAL", "NaN",  "‘Abuse of entrusted power for private gain’,1 which can be instigated by individuals or organizations. In the GRI Standards, corruption includes practices such as bribery, facilitation payments, fraud, extortion, collusion, and money laundering. It also includes an offer or receipt of any gift, loan, fee, reward, or other advantage to or from any person as an inducement to do something that is dishonest, illegal, or a breach of trust in the conduct of the enterprise’s business.2 This can include cash or in-kind benefits, such as free goods, gifts, and holidays, or special personal services provided for the purpose of an improper advantage, or that can result in moral pressure to receive such an advantage.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SERVICES_SUPPORTED", "ORGANIZATIONAL, SOCIETAL", "LIST_OF_TERMS",  "Services that provide a public benefit either through direct payment of operating costs or through staffing the facility or service with an organization’s own employees.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SECTORS", "SOCIETAL", "LIST_OF_TERMS",  "Subdivision of an economy, society or sphere of activity, defined on the basis of some common characteristic. Sector types can include classifications such as the public or private sector, and industry specific categories such as the education, technology, or financial sectors.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ANTI_COMPETITIVE_BEHAVIOR", "ORGANIZATIONAL, HUMAN_RESOURCES", "LIST_OF_TERMS",  "Action of the organization or employees that can result in collusion with potential competitors, with the purpose of limiting the effects of market competition.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ANTI_TRUST_AND_MONOPOLY_PRACTICE", "ORGANIZATIONAL, SOCIETAL", "LIST_OF_TERMS",  "Action of the organization that can result in collusion to erect barriers for entry to the sector, or another collusive action that prevents competition.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RECLAIMED", "SOCIETAL, OGRANIZATIONAL, LOGISTICIS", "DOCUMENT",  "Refers to collecting, reusing, or recycling products and their packaging materials at the end of their useful lives.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RECYCLED_INPUT_MATERIAL", "OGRANIZATIONAL, LOGISTICS", "LIST_OF_TERMS",  "material that replaces virgin materials, which are purchased or obtained from internal or external sources, and that are not by-products and non-product outputs (NPO) produced by the organization", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_RECYCLED_INPUT_MATERIALS_USED", "WEIGHT", "NUMBER",  "Total weight of materials used by an organization to produce a product or products, that were recycled, expressed in a unit of measurement such as kg, ton, etc. This includes the following materials: raw materials, i.e., natural resources used for conversion to products or services, such as ores, minerals, and wood; associated process materials, i.e., materials that are needed for the manufacturing process but are not part of the final product, such as lubricants for manufacturing machinery; semi-manufactured goods or parts, including all forms of materials and components other than raw materials that are part of the final product; materials for packaging purposes, including paper, cardboard and plastics;", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_INPUT_MATERIALS_USED", "WEIGHT", "NUMBER",  "Total weight of materials used by an organization to produce a product or products, expressed in a unit of measurement such as kg, ton, etc. This includes the following materials: raw materials, i.e., natural resources used for conversion to products or services, such as ores, minerals, and wood; associated process materials, i.e., materials that are needed for the manufacturing process but are not part of the final product, such as lubricants for manufacturing machinery; semi-manufactured goods or parts, including all forms of materials and components other than raw materials that are part of the final product; materials for packaging purposes, including paper, cardboard and plastics;", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RENEWABLE_ENERGY_SOURCE", "ENVIRONMENTAL, ENERGY", "SINGLE_TERM",  "Energy source that is capable of being replenished in a short time through ecological cycles or agricultural processes. Renewable energy sources can include geothermal, wind, solar, hydro, and biomass.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("NON_RENEWABLE_ENERGY_SOURCE", "EENVIRONMENTAL, NERGY", "SINGLE_TERM",  "energy source that cannot be replenished, reproduced, grown or generated in a short time period through ecological cycles or agricultural processes. Non-renewable energy sources can include fuel distilled from petroleum or crude oil, such as gasoline, diesel fuel, jet fuel, and heating oil; natural gas, such as compressed natural gas (CNG), and liquefied natural gas (LNG); fuels extracted from natural gas processing and petroleum refining, such as butane, propane, and liquefied petroleum gas (LPG); coal; and nuclear power.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_ENERGY_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Energy consumption of an organization, measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_FUEL_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Fuel consumption of an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_ELECTRICITY_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Electricity consumption of an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_COOLING_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Cooling consumption of an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_HEATING_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Heating consumption of an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_STEAM_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Steam consumption of an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_ELECTRICITY_SOLD", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL, FINANCIAL", "NUMBER",  "Electricity sold by an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_COOLING_SOLD", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL, FINANCIAL", "NUMBER",  "Cooling sold by an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_HEATING_SOLD", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL, FINANCIAL", "NUMBER",  "Heating sold by an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_STEAM_SOLD", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL, FINANCIAL", "NUMBER",  "Steam sold by an organization measured in Joules, Watt-hours or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EXTERNAL_ENERGY_CONSUMPTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "The reporting organization can identify energyconsumption outside of the organization by assessing whether an activity’s energy consumption: contributes significantly to the organization’s total anticipated energy consumption outside of the organization; offers potential for reductions the organization can undertake or influence; contributes to climate change-related risks, such as financial, regulatory, supply chain, product and customer, litigation, and reputational risks; is deemed material by stakeholders, such as customers, suppliers, investors, or civil society; results from outsourced activities previously performed in-house, or that are typically performed in-house by other organizations in the same sector; has been identified as significant for the organization’s sector; meets any additional criteria for determining relevance, developed by the organization or by organizations in its sector.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ENERGY_REDUCTION", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "NUMBER",  "Amount of energy no longer used or needed to carry out the same processes or tasks, e.g. measured in Joules or Watt-hours. Note: Energy reduction does not include overall reduction in energy consumption from reducing production capacity or outsourcing organizational activities.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CONSERVATION_AND_EFFICIENCY_INITIATIVE", "ENVIRONMENTAL, ENERGY, ORGANIZATIONAL", "DOCUMENT",  "Organizational or technological modification that allows a defined process or task to be carried out using less energy Note: Conservation and efficiency initiatives include process redesign, the conversion and retrofitting of equipment such as energy-efficient lighting, or the elimination of unnecessary energy use due to changes in behavior.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("BASELINE", "ENVIRONMENTAL, SOCIETAL, ORGANIZATIONAL, ENERGY", "NUMBER",  "Starting point used for comparisons. Note: In the context of energy and emissions reporting, the baseline is the projected energy consumption or emissions in the absence of any reduction activity.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("BASE_YEAR", "ENVIRONMENTAL, ORGANIZATIONAL, SOCIETAL, TIME, ENERGY", "NUMBER",  "Historical datum (such as year) against which a measurement is tracked over time.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_VOLUME_OF_WATER_WITHDRAWN", "ENVIRONMENTAL, WATER", "NUMBER",  "The sum of all water drawn into the boundaries of the organization from all sources for any use over the course of the reporting period (e.g., measured in cubic meters). Note: Sources of water withdrawal can include surface water, ground water, rainwater, and municipal water supply.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_SOURCE_SIZE", "ENVIRONMENTAL, WATER", "NUMBER",  "The size of the water source that is significanly affected by withdrawal from an organization  (e.g., measured in cubic meters). Note: Sources of water withdrawal can include surface water, ground water, rainwater, and municipal water supply. Withdrawals from water bodies that are recognized by professionals to be particularly sensitive due to their relative size, function, or status as a rare, threatened, or endangered system, or that support a particular endangered species of plant or animal. Any withdrawal from a wetland listed in the Ramsar Convention or any other nationally or internationally proclaimed conservation area, regardless of the rate of withdrawal.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LOCAL_COMMUNITY", "ENVIRONMENTAL, SOCIETAL", "NUMBER",  "Persons or groups of persons living and/or working in any areas that are economically, socially or environmentally impacted (positively or negatively) by an organization’s operations Note: The local community can range from persons living adjacent to an organization’s operations, to those living at a distance who are still likely to be impacted by these operations.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("INDIGENOUS_PEOPLES", "ENVIRONMENTAL, WATER", "NUMBER",  "The size of the water source that is significanly affected by withdrawal from an organization  (e.g., measured in cubic meters). Note: Sources of water withdrawal can include surface water, ground water, rainwater, and municipal water supply. Withdrawals from water bodies that are recognized by professionals to be particularly sensitive due to their relative size, function, or status as a rare, threatened, or endangered system, or that support a particular endangered species of plant or animal. Any withdrawal from a wetland listed in the Ramsar Convention or any other nationally or internationally proclaimed conservation area, regardless of the rate of withdrawal.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_RECYCLING_AND_REUSE", "ENVIRONMENTAL, WATER", "DOCUMENT",  "Act of processing used water and wastewater through another cycle before discharge to final treatment and discharge to the environment. Water recycling and reuse can include wastewater recycled back in the same process or higher use of recycled water in the process cycle; wastewater recycled and reused in a different process, but within the same facility; and wastewater reused at another of the organization’s facilities.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("TOTAL_WATER_WITHDRAWAL", "ENVIRONMENTAL, WATER", "NUMBER",  "The sum of all water drawn into the boundaries of the organization from all sources for any use over the course of the reporting period, measured in volume (e.g. cubic meters). Sources of water withdrawal can include surface water, ground water, rainwater, and municipal water supply.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_STRESS", "ENVIRONMENTAL, WATER", "DOCUMENT",  "Ability, or lack thereof, to meet the human and ecological demand for water. Water stress can refer to the availability, quality, or accessibility of water and is based on subjective elements and is assessed differently depending on societal values, such as the suitability of water for drinking or the requirements to be afforded to ecosystems.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_STEWARDSHIP", "SOCIETAL, ENVIRONMENTAL, WATER", "DOCUMENT",  "use of water that is socially equitable, environmentally sustainable, and economically beneficial, achieved through a stakeholder-inclusive process that involves facility- and catchment-based actions.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RUNOFF", "ENVIRONMENTAL, WATER", "NUMBER",  "Part of precipitation that flows towards a river on the ground surface (i.e., surface runoff) or within the soil (i.e., subsurface flow). Measured in unit of volume by time, e.g., cubic meters per second. This definition is based on the United Nations Educational, Scientific and Cultural Organization (UNESCO), UNESCO International Glossary of Hydrology, 2012.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_DISCHARGE", "ENVIRONMENTAL, WATER", "NUMBER",  "Sum of effluents, used water, and unused water released to surface water, groundwater, seawater, or a third party, for which the organization has no further use, over the course of the reporting period. Measured in volume, e.g, cubic meters. Note 1: Water can be released into the receiving waterbody either at a defined discharge point (pointsource discharge) or dispersed over land in an undefined manner (non-point-source discharge). Note 2: Water discharge can be authorized (in accordance with discharge consent) or unauthorized (if discharge consent is exceeded).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_WITHDRAWN", "ENVIRONMENTAL, WATER", "NUMBER",  "Sum of all water drawn from surface water, groundwater, seawater, or a third party for any use over the course of the reporting period. Measured in volume, e.g, cubic meters.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_CONSUMED", "ENVIRONMENTAL, WATER", "NUMBER",  "Sum of all water that has been withdrawn and incorporated into products, used in the production of crops or generated as waste, has evaporated, transpired, or been consumed by humans or livestock, or is polluted to the point of being unusable by other users, and is therefore not released back to surface water, groundwater, seawater, or a third party over the course of the reporting period.  Measured in volume, e.g, cubic meters.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EFFLUENT", "ENVIRONMENTAL, WATER", "DOCUMENTATION",  "Treated or untreated wastewater that is discharged", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CATCHMENT", "LOCATION, ENVIRONMENTAL, WATER", "DOCUMENTATION",  "Area of land from which all surface runoff and subsurface water, flows through a sequence of streams, rivers, aquifers, and lakes into the sea or another outlet at a single river mouth, estuary, or delta.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("FRESHWATER", "WATER", "DOCUMENTATION",  "Water with concentration of total dissolved solids equal to or below 1,000 mg/L. This definition is based on ISO 14046:2014; the United States Geological Survey (USGS), Water Science Glossary of Terms, water.usgs.gov/edu/dictionary.html, accessed on 1 June 2018; and the World Health Organization (WHO), Guidelines for Drinking-water Quality, 2017.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GROUNDWATER", "WATER", "DOCUMENTATION",  "Water that is being held in, and that can be recovered from, an underground formation. This definition comes from ISO 14046:2014.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SEAWATER", "WATER", "DOCUMENTATION",  "Water in a sea or in an ocean. This definition comes from ISO 14046:2014.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PRODUCED_WATER", "WATER", "DOCUMENTATION",  "Water that enters an organization’s boundary as a result of extraction (e.g., crude oil), processing (e.g., sugar cane crushing), or use of any raw material, and has to consequently be managed by the organization. This definition is based on CDP, CDP Water Security Reporting Guidance, 2018.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SURFACE_WATER", "WATER", "DOCUMENTATION",  "Water that occurs naturally on the Earth’s surface in ice sheets, ice caps, glaciers, icebergs, bogs, ponds, lakes, rivers, and streams. This definition is based on CDP, CDP Water Security Reporting Guidance, 2018.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("THIRD_PARTY_WATER", "WATER", "DOCUMENTATION",  "Municipal water suppliers and municipal wastewater treatment plants, public or private utilities, and other organizations involved in the provision, transport, treatment, disposal, or use of water and effluent.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WATER_STORAGE", "WATER", "NUMBER",  "Water held in water storage facilities or reservoirs, measured in volume (e.g., in cubic meters, liters, etc.).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PROTECTED_AREAS", "BIODIVERSITY, LOCATION", "LIST_OF_NUMBERS",  "Geographic area that is designated, regulated, or managed to achieve specific conservation objectives, represented as e.g., list of <latitude,longitude> tuples (bounding box).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("AREAS_OF_HIGH_BIODIVERSITY_VALUE", "BIODIVERSITY, LOCATION", "LIST_OF_NUMBERS",  "Area not subject to legal protection, but recognized for important biodiversity features by a number of governmental and non-governmental organizations. Represented as e.g., list of <latitude,longitude> tuples (bounding box).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SIGNIFICANT_IMPACT_ON_BIODIVERSITY", "BIODIVERSITY, LOCATION", "DOCUMENTATION",  "Impact that can adversely affect the integrity of a geographic area or region, either directly or indirectly, by substantially changing its ecological features, structures, and functions across its whole area, and over the long term, so that habitat, its population levels, and the particular species that make the habitat important cannot be sustained.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("AREA_PROTECTED", "BIODIVERSITY, LOCATION", "LIST_OF_NUMBERS",  "Area that is protected from any harm during operational activities, and where the environment remains in its original state with a healthy and functioning ecosystem. Represented as e.g., list of <latitude,longitude> tuples (bounding box).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("AREA_RESTORED", "BIODIVERSITY, LOCATION", "LIST_OF_NUMBERS",  "Area that was used during or affected by operational activities, and where remediation measures have either restored the environment to its original state, or to a state where it has a healthy and functioning ecosystem. Represented as e.g., list of <latitude,longitude> tuples (bounding box).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("BIOGENIC_CARBON_DIOXIDE_EMISSIONS", "ENVIRONMENTAL, EMISSIONS", "NUMBER",  "Emission of CO2 from the combustion or biodegradation of biomass, measured e.g., in unit of volume per emitter (e.g., metric tons per capita)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CARBON_DIOXIDE_EQUIVALENT", "ENVIRONMENTAL, EMISSIONS", "TERM",  "Measure used to compare the emissions from various types of greenhouse gas (GHG) based on their global warming potential (GWP) Note: The CO2 equivalent for a gas is determined by multiplying the metric tons of the gas by the associated GWP.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GLOBAL_WARMING_POTENTIAL", "ENVIRONMENTAL, EMISSIONS", "NUMBER",  "Value describing the radiative forcing impact of one unit of a given GHG relative to one unit of CO2 over a given period of time Note: GWP values convert GHG emissions data for non-CO2 gases into units of CO2 equivalent.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("DIRECT_SCOPE_1_CHG_EMISSIONS", "ENVIRONMENTAL, EMISSIONS", "NUMBER",  "Greenhouse Gas (GHG) emissions from sources that are owned or controlled by an organization measured e.g. in kg or multiples. Note 1: A GHG source is any physical unit or process that releases GHG into the atmosphere. Note 2: Direct (Scope 1) GHG emissions can include the CO2 emissions from fuel consumption.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("INDIRECT_SCOPE_2_CHG_EMISSIONS", "ENVIRONMENTAL, EMISSIONS", "NUMBER",  "Greenhouse Gas (GHG) emissions that result from the generation of purchased or acquired electricity, heating, cooling, and steam consumed by an organization.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("OTHER_INDIRECT_SCOPE_3_CHG_EMISSIONS", "ENVIRONMENTAL, EMISSIONS", "NUMBER",  "Indirect Greenhouse Gas (GHG) emissions not included in energy indirect (Scope 2) GHG emissions that occur outside of the organization, including both upstream and downstream emissions.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ODS", "ENVIRONMENTAL, EMISSIONS", "TERM",  "Ozone-depleting substance (ODS). Substance with an ozone depletion potential (ODP) greater than 0 that can deplete the stratospheric ozone layer Note: Most ODS are controlled under the United Nations Environment Programme (UNEP), ‘Montreal Protocol on Substances that Deplete the Ozone Layer’, 1987, and its amendments, and include chlorofluorocarbons (CFCs), hydrochlorofluorocarbons (HCFCs), halons, and methyl bromide.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CFC_11_TRICHLOROFLUOROMETHANE", "ENVIRONMENTAL, EMISSIONS", "TERM",  "CFC11 (trichlorofluoromethane) equivalent measure used to compare various substances based on their relative ozone depletion potential (ODP) Note: The reference level of 1 is the potential of CFC-11 (trichlorofluoromethane) and CFC-12 (dichlorodifluoromethane) to cause ozone depletion.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SIGNIFICANT_AIR_EMISSIONS", "ENVIRONMENTAL, EMISSIONS", "NUMBER",  "Air emission regulated under international conventions and/or national laws or regulations Note: Significant air emissions include those listed on environmental permits for an organization’s operations. Measured in kg. or multiples.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WASTE", "ENVIRONMENTAL, WASTE", "LIST_OF_TERMS",  "Anything that the holder discards, intends to discard, or is required to discard. Note 1: Waste can be defined according to the national legislation at the point of generation. Note 2: A holder can be the reporting organization, an entity in the organization’s value chain upstream or downstream (e.g., supplier or consumer), or a waste management organization, among others. Note 3: This definition is based on the United Nations Environment Programme (UNEP), Basel Convention on the Control of Transboundary Movements of Hazardous Wastes and Their Disposal, 1989.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CIRCULARITY_MEASURE", "ENVIRONMENTAL, WASTE", "LIST_OF_TERMS",  "Measures taken to retain the value of products, materials, and resources and redirect them back to use for as long as possible with the lowest carbon and resource footprint possible, such that fewer raw materials and resources are extracted and waste generation is prevented.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PREPARATION_FOR_REUSE", "ENVIRONMENTAL, WASTE", "LIST_OF_TERMS",  "Checking, cleaning, or repairing operations, by which products or components of products that have become waste are prepared to be put to use for the same purpose for which they were conceived", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RECYCLING", "ENVIRONMENTAL, WASTE", "TERMM",  "Reprocessing of products or components of products that have become waste, to make new materials Note: This definition is based on the United Nations Environment Programme (UNEP), Basel Convention on the Control of Transboundary Movements of Hazardous Wastes and Their Disposal, 1989.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RECOVERY", "ENVIRONMENTAL, WASTE", "LIST_OF_TERMS",  "Any operation wherein products, components of products, or materials that have become waste are prepared to fulfill a purpose in place of new products, components, or materials that would otherwise have been used for that purpose", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("DISPOSAL", "ENVIRONMENTAL, WASTE", "LIST_OF_TERMS",  "Any operation which is not recovery, even where the operation has as a secondary consequence the recovery of energy. Note 1: Disposal is the end-of-life management of discarded products, materials, and resources in a sink or through a chemical or thermal transformation that makes these products, materials, and resources unavailable for further use. Note 2: This definition comes from the European Union (EU), Waste Framework Directive, 2008 (Directive 2008/98/EC).", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("INCINERATION", "ENVIRONMENTAL, WASTE", "TERM",  "Controlled burning of waste at high temperatures. Note 1: Incineration of waste can be carried out with or without energy recovery. Incineration with energy recovery is also known as waste to energy. In the context of waste reporting, incineration with energy recovery is considered a disposal operation. Note 2: This definition comes from the United Nations (UN), Glossary of Environment Statistics, Studies in Methods, Series F, No. 67, 1997.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LANDFILLING", "ENVIRONMENTAL, WASTE", "TERM",  "Final depositing of solid waste at, below, or above ground level at engineered disposal sites Note 1: In the context of waste reporting, landfilling refers to depositing of solid waste in sanitary landfills, and excludes uncontrolled waste disposal such as open burning and dumping. Note 2: This definition comes from the United Nations (UN), Glossary of Environment Statistics, Studies in Methods, Series F, No. 67, 1997.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("ENVIRONMENTAL_LAWS_AND_REGULATIONS", "ENVIRONMENTAL, LEGAL, ORGANIZATIONAL", "DOCUMENTATION",  "Laws and regulations related to all types of environmental issues applicable to the organization. Note 1: Environmental issues can include those such as emissions, effluents, and waste, as well as material use, energy, water, and biodiversity. Note 2: Environmental laws and regulations can include binding voluntary agreements that are made with regulatory authorities and developed as a substitute for implementing a new regulation. Note 3: Voluntary agreements can be applicable if the organization directly joins the agreement, or if public agencies make the agreement applicable to organizations in their territory through legislation or regulation.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SUPPLIER_SCREENING", "ORGANIZATIONAL", "DOCUMENTATION",  "Formal or documented process that applies a set of performance criteria as one of the factors in determining whether to proceed in a relationship with a supplier.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PARENTAL_LEAVE", "ORGANIZATIONAL, HUMAN_RESOURCES", "TERM",  "Leave granted to men and women employees on the grounds of the birth of a child.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("STANDARD_BENEFITS", "ORGANIZATIONAL, HUMAN_RESOURCES", "LIST_OF_TERMS",  "Benefits typically offered to the majority of full-time employees Note: Standard benefits do not need to be offered to every single full-time employee of the organization. The intention of reporting on standard benefits is to disclose what full-time employees can reasonably expect.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("EMPLOYEE_TURNOVER", "ORGANIZATIONAL, HUMAN_RESOURCES", "TERM",  "Employees who leave the organization voluntarily or due to dismissal, retirement, or death in service.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SIGNIFICANT_OPERATIONAL_CHANGE", "ORGANIZATIONAL, HUMAN_RESOURCES", "TERM",  "Alteration to the organization’s pattern of operations that can potentially have significant positive or negative impacts on workers performing the organization’s activities Note: Significant operational change can include restructuring, outsourcing of operations, closures, expansions, new openings, takeovers, sale of all or part of the organization, or mergers.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORK_RELATED_HAZARD", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Source or situation with the potential to cause injury or ill health. Note 1: Hazards can be: physical (e.g., radiation, temperature extremes, constant loud noise, spills on floors or tripping hazards, unguarded machinery, faulty electrical equipment); ergonomic (e.g., improperly adjusted workstations and chairs, awkward movements, vibration); chemical (e.g., exposure to solvents, carbon monoxide, flammable materials, or pesticides); biological (e.g., exposure to blood and bodily fluids, fungi, bacteria, viruses, or insect bites); psychosocial (e.g., verbal abuse, harassment, bullying); related to work-organization (e.g., excessive workload demands, shift work, long hours, night work, workplace violence). Note 2: This definition is based on International Labour Organization (ILO) Guidelines on Occupational Safety and Health Management Systems from 2001 and ISO 45001:2018.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("HIERARCHY_OF_CONTROL", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Systematic approach to enhance occupational health and safety, eliminate hazards, and minimize risks. Note 1: The hierarchy of controls seeks to protect workers by ranking the ways in which hazards can be controlled. Each control in the hierarchy is considered less effective than the one before it. The priority is to eliminate the hazard, which is the most effective way to control it. Note 2: The International Labour Organization (ILO) Guidelines on Occupational Safety and Health Management Systems from 2001 and ISO 45001:2018 list the following preventive and protective measures in the following order of priority: eliminate the hazard/risk; substitute the hazard/risk with less hazardous processes, operations, materials, or equipment; control the hazard/risk at source, through the use of engineering controls or organizational measures; minimize the hazard/risk by the design of safe work systems, which include administrative control measures; where residual hazards/risks cannot be controlled by collective measures, provide for appropriate personal protective equipment, including clothing, at no cost, and implement measures to ensure its use and maintenance.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("OCCUPATIONAL_HEALTH_AND_SAFETY_MANAGEMENT_SYSTEM", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Services entrusted with essentially preventive functions, and responsible for advising the employer, the workers, and their representatives in the undertaking, on the requirements for establishing and maintaining a safe and healthy work environment, which will facilitate optimal physical and mental health in relation to work and the adaptation of work to the capabilities of workers in the light of their state of physical and mental health. Note 1: Functions of occupational health services include: surveillance of factors in the work environment, including any sanitary installations, canteens, and housing provided to workers, or in work practices, which might affect workers’ health; surveillance of workers' health in relation to work; advice on occupational health, safety, and hygiene; advice on ergonomics, and on individual and collective protective equipment; promotion of the adaptation of work to the worker; organization of first aid and emergency treatment. Note 2: This definition comes from the International Labour Organization (ILO) Convention 161, ‘Occupational Health Services Convention’, 1985.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORK_RELATED_INCIDENT", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Occurrence arising out of or in the course of work that could or does result in injury or ill health. Note 1: This definition is based on ISO 45001:2018. Note 2: Incidents might be due to, for example, electrical problems, explosion, fire; overflow, overturning, leakage, flow; breakage, bursting, splitting; loss of control, slipping, stumbling and falling; body movement without stress; body movement under/with stress; shock, fright; workplace violence or harassment (e.g., sexual harassment). Note 3: An incident that results in injury or ill health is often referred to as an ‘accident’. An incident that has the potential to result in injury or ill health but where none occurs is often referred to as a ‘close call’, ‘near-miss’, or ‘near-hit’.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORK_RELATED_INJURY", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Negative impacts on health arising from exposure to hazards at work. Note 1: This definition is based on the International Labour Organization (ILO), Guidelines on Occupational Safety and Health Management Systems, ILO-OSH 2001, 2001.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RECORDABLE_WORK_RELATED_INJURY", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Work-related injury or ill health that results in any of the following: death, days away from work, restricted work or transfer to another job, medical treatment beyond first aid, or loss of consciousness; or significant injury or ill health diagnosed by a physician or other licensed healthcare professional, even if it does not result in death, days away from work, restricted work or job transfer, medical treatment beyond first aid, or loss of consciousness. Note: This definition is based on the United States Occupational Safety and Health Administration, General recording criteria 1904.7, https://www.osha.gov/pls/oshaweb/owadisp.show_document?p_ table=STANDARDS&p_id=9638, accessed on 1 June 2018.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("HIGH_CONSEQUENCE_WORK_RELATED_INJURY", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Work-related injury that results in a fatality or in an injury from which the worker cannot, does not, or is not expected to recover fully to pre-injury health status within 6 months.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("OCCUPATIONAL_HEALTH_SERVICE", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Services entrusted with essentially preventive functions, and responsible for advising the employer, the workers, and their representatives in the undertaking, on the requirements for establishing and maintaining a safe and healthy work environment, which will facilitate optimal physical and mental health in relation to work and the adaptation of work to the capabilities of workers in the light of their state of physical and mental health", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORKER_PARTICIPATION", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Workers’ involvement in decision-making. Note 1: Worker participation might be carried out through workers’ representatives. Note 2: Worker participation and consultation are two distinct terms with specific meanings. See definition of ‘worker consultation’.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORKER_CONSULTATION", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Seeking of workers’ views before making a decision Note 1: Worker consultation might be carried out through workers’ representatives. Note 2: Consultation is a formal process, whereby management takes the views of workers into account when making a decision. Therefore, consultation needs to take place before the decision is made. It is essential to provide timely information to workers or their representatives in order for them to provide meaningful and effective input before decisions are made. Genuine consultation involves dialogue. Note 3: Worker participation and consultation are two distinct terms with specific meanings. See definition of ‘worker participation’.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("FORMAL_JOINT_MANAGEMENT_WORKER_HEALTH_AND_SAFETY_COMMITTEE", "HEALTH_AND_SAFETY, HUMAN_RESOURCES, SAFETY_AND_SECURITY", "TERM",  "Committee composed of management and worker representatives, whose function is integrated into an organizational structure, and which operates according to agreed written policies, procedures, and rules, and helps facilitate worker participation and consultation on matters of occupational health and safety", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("HEALTH_PROMOTION", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Process of enabling people to increase control over and improve their health Note 1: The terms ‘health promotion’, ‘wellbeing’, and ‘wellness’ are often used interchangeably. Note 2: This definition comes from the World Health Organization (WHO), ‘Ottawa Charter for Health Promotion’, 1986.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("OCCUPATIONAL_HEALTH_AND_SAFETY_RISK", "HEALTH_AND_SAFETY, HUMAN_RESOURCES, SAFETY_AND_SECURITY", "TERM",  "Combination of the likelihood of occurrence of a work-related hazardous situation or exposure, and the severity of injury or ill health that can be caused by the situation or exposure Note: This definition is based on ISO 45001:2018.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("WORK_RELATED_ILL_HEALTH", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Negative impacts on health arising from exposure to hazards at work Note 1: This definition is based on the International Labour Organization (ILO), Guidelines on Occupational Safety and Health Management Systems, ILO-OSH 2001, 2001.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("RECORDABLE_WORK_RELATED_ILL_HEALTH", "HEALTH_AND_SAFETY, HUMAN_RESOURCES", "TERM",  "Work-related injury or ill health that results in any of the following: death, days away from work, restricted work or transfer to another job, medical treatment beyond first aid, or loss of consciousness; or significant injury or ill health diagnosed by a physician or other licensed healthcare professional, even if it does not result in death, days away from work, restricted work or job transfer, medical treatment beyond first aid, or loss of consciousness Note: This definition is based on the United States Occupational Safety and Health Administration, General recording criteria 1904.7, https://www.osha.gov/pls/oshaweb/owadisp.show_document?p_ table=STANDARDS&p_id=9638, accessed on 1 June 2018.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CONTINUED_EMPLOYABILITY", "HUMAN_RESOURCES", "TERM",  "Adaptation to the changing demands of the workplace through the acquisition of new skills.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("REGULAR_PERFORMANCE_AND_CAREER_DEVELOPMENT_REVIEW", "HUMAN_RESOURCES", "TERM",  "Review based on criteria known to the employee and his or her superior Note 1: The review is undertaken with the knowledge of the employee at least once per year. Note 2: The review can include an evaluation by the employee’s direct superior, peers, or a wider range of employees. The review can also involve the human resources department.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("BASIC_SALARY", "HUMAN_RESOURCES, FINANCIAL", "NUMBER",  "Fixed, minimum amount paid to an employee for performing his or her duties, excluding any additional remuneration, such as payments for overtime working or bonuses. Expressed in a unit of currency (e.g., US Dollars or Swedish Crowns)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("REMUNERATION", "HUMAN_RESOURCES, FINANCIAL", "NUMBER",  "Basic salary plus additional amounts paid to a worker. Note: Examples of additional amounts paid to a worker can include those based on years of service, bonuses including cash and equity such as stocks and shares, benefit payments, overtime, time owed, and any additional allowances, such as transportation, living and childcare allowances. Expressed in a unit of currency (e.g., US Dollars or Swedish Crowns)", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GOVERNANCE_BODY", "ORGANIZATIONAL", "TERM",  "Committee or board responsible for the strategic guidance of the organization, the effective monitoring of management, and the accountability of management to the broader organization and its stakeholders.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("INDICATOR_OF_DIVERSITY", "SOCIETAL, HUMAN_RESOURCES, ORGANIZATIONAL", "LIST_OF_TERMS",  "Indicator of diversity for which the organization gathers data Note: Examples of indicators of diversity can include age, ancestry and ethnic origin, citizenship, creed, disability, and gender.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("VULNERABLE_GROUP", "SOCIETAL, HUMAN_RESOURCES, HUMAN_RIGHTS", "TERM",  "Set or subset of persons with some specific physical, social, political, or economic condition or characteristic that places the group at a higher risk of suffering a burden, or at a risk of suffering a disproportionate burden of the social, economic or environmental impacts of the organization’s operations Note 1: Vulnerable groups can include children and youth, the elderly, people with disabilities, excombatants, the internally displaced, refugees or returning refugees, HIV/AIDS-affected households, indigenous peoples, and ethnic minorities. Note 2: Vulnerabilities and impacts can differ by gender.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("DISCRIMINATION", "ORGANIZATIONAL, HUMAN_RESOURCES, HUMAN_RIGHTS", "LIST_OF_TERMS",  "Act and result of treating persons unequally by imposing unequal burdens or denying benefits instead of treating each person fairly on the basis of individual merit Note: Discrimination can also include harassment, defined as a course of comments or actions that are unwelcome, or should reasonably be known to be unwelcome, to the person towards whom they are addressed.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("FREEDOM_OF_ASSOCIATION", "HUMAN_RESOURCES, HUMAN_RIGHTS", "LIST_OF_TERMS",  "Right of employers and workers to form, to join and to run their own organizations without prior authorization or interference by the state or any other entity.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("CHILD", "HUMAN_RESOURCES, HUMAN_RIGHTS", "TERM",  "Person under the age of 15 years, or under the age of completion of compulsory schooling, whichever is higher Note 1: Exceptions can occur in certain countries where economies and educational facilities are insufficiently developed and a minimum age of 14 years applies. These countries of exception are specified by the International Labour Organization (ILO) in response to a special application by the country concerned and in consultation with representative organizations of employers and workers. Note 2: The ILO Convention 138, ‘Minimum Age Convention’, 1973, refers to both child labor and young workers.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("FORCED_OR_COMPULSORY_LABOR", "HUMAN_RESOURCES, HUMAN_RIGHTS", "TERM",  "All work and service that is exacted from any person under the menace of any penalty and for which the said person has not offered herself or himself voluntarily Note 1: The most extreme examples of forced or compulsory labor are slave labor and bonded labor, but debts can also be used as a means of maintaining workers in a state of forced labor. Note 2: Indicators of forced labor include withholding identity papers, requiring compulsory deposits, and compelling workers, under threat of firing, to work extra hours to which they have not previously agreed. Note 3: This definition is based on International Labour Organization (ILO) Convention 29, ‘Forced Labour Convention’, 1930.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SECURITY_PERSONNEL", "HUMAN_RESOURCES, SAFETY_AND_SECURITY", "TERM",  "Individuals employed for the purposes of guarding property of the organization; crowd control; loss prevention; and escorting persons, goods, and valuables", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("HUMAN_RIGHTS_CLAUSES", "HUMAN_RIGHTS", "DOCUMENT",  "Specific terms in a written agreement that define minimum expectations of performance with respect to human rights as a requirement for investment.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("HUMAN_RIGHTS_REVIEWS", "HUMAN_RIGHTS", "DOCUMENT",  "Formal or documented assessment process that applies a set of human rights performance criteria.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("LOCAL_COMMUNITY", "HUMAN_RIGHTS", "DOCUMENT",  "persons or groups of persons living and/or working in any areas that are economically, socially or environmentally impacted (positively or negatively) by an organization’s operations Note: The local community can range from persons living adjacent to an organization’s operations, to those living at a distance who are still likely to be impacted by these operations.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("COMMUNITY_DEVELOPMENT_PROGRAME", "HUMAN_RIGHTS", "DOCUMENT",  "Plan that details actions to minimize, mitigate, or compensate for adverse social and/or economic impacts, and/or to identify opportunities or actions to enhance positive impacts of a project on the community", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("COMMUNITY_OPERATION", "HUMAN_RIGHTS", "DOCUMENT",  "An operation, considered alone or in combination with the characteristics of local communities, that has a higher than average potential of negative impacts, or actual negative impacts, on the social, economic or environmental well-being of local communities Note: Examples of negative impacts on local communities can include impacts to local community health and safety.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SUPPLIER_SCREENING", "LOGISTICS, ORGANIZATIONAL", "DOCUMENT",  "Formal or documented process that applies a set of performance criteria as one of the factors in determining whether to proceed in a relationship with a supplier.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("POLITICAL_CONTRIBUTION", "FINANCIAL, ORGANIZATIONAL", "DOCUMENT",  "Financial or in-kind support given directly or indirectly to political parties, their elected representatives, or persons seeking political office Note 1: Financial contributions can include donations, loans, sponsorships, retainers, or the purchase of tickets for fundraising events. Note 2: In-kind contributions can include advertising, use of facilities, design and printing, donation of equipment, or the provision of board membership, employment or consultancy work for elected politicians or candidates for office.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("INDIRECT_POLITICAL_CONTRIBUTION", "FINANCIAL, ORGANIZATIONAL", "LIST_OF_TERMS",  "Financial or in-kind support to political parties, their representatives, or candidates for office made through an intermediary organization such as a lobbyist or charity, or support given to an organization such as a think tank or trade association linked to or supporting particular political parties or causes.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("PRODUCT_AND_SERVICE_INFORMATION_AND_LABELING", "LOGISTICS, ORGANIZATIONAL", "LIST_OF_TERMS",  "Information and labeling are used synonymously, and describe communication delivered with the product or service, describing its characteristics", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("MARKETING_COMMUNICATION", "LOGISTICS, ORGANIZATIONAL", "DOCUMENT",  "combination of strategies, systems, methods, and activities used by the organization to promote its reputation, brands, products, and services to target audiences Note: Marketing communications can include activities such as advertising, personal selling, promotion, public relations, social media and sponsorship.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("BREACH_OF_CUSTOMER_PRIVACY", "SAFETY_AND_SECURITY, ORGANIZATIONAL", "DOCUMENT",  "Non-compliance with existing legal regulations and (voluntary) standards regarding the protection of customer privacy.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("SUBSTANTIATED_COMPLAINT", "SAFETY_AND_SECURITY, ORGANIZATIONAL", "DOCUMENT",  "Written statement by regulatory or similar official body addressed to the organization that identifies breaches of customer privacy, or a complaint lodged with the organization that has been recognized as legitimate by the organization.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r14-REC", "NaN", "RECOMMENDATION", "When compiling the information the rorting organization should include <ul><li>(a) the overall vision and strategy for the short-term, medium-term, and long-term, with respect to managing the significant economic, environmental, and social impacts that the organization causes, contributes to, or that are directly linked to its activities, products or services as a result of relationships with others (such as suppliers and persons or organizations in local communities</li><li>(b) strategic priorities and key topics for the short and medium-term with respect to sustainability, including observance of internationally-recognized standards and how such standards relate to long-term organizational strategy and success</li><li>(c) broader trends (such as macroeconomic or political) affecting the organization and influencing its sustainability priorities</li><li>(d) key events, achievements, and failures during the reporting period;</li><li> (e) views on performance with respect to targets;</li><li> (f) outlook on the organization’s main challenges and targets for the next year and goals for the coming 3–5 years</li><li>(g) other items pertaining to the organization’s strategic approach.</li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r15-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in this disclosure, the reporting organization should include:<ul><li>a description of its significant economic, environmental and social impacts, and associated challenges and opportunities. This includes the effects on stakeholders and their rights as defined by national laws and relevant internationally-recognized standards;</li><li>the range of reasonable expectations and interests of the organization’s stakeholders;</li><li>an explanation of the approach to prioritizing these challenges and opportunities;</li><li>key conclusions about progress in addressing these topics and related performance in the reporting period, including an assessment of reasons for underperformance or overperformance;</li><li>a description of the main processes in place to address performance, and relevant changes;</li><li>the impact of sustainability trends, risks, and opportunities on the long-term prospects and financial performance of the organization;</li><li>information relevant to financial stakeholders or that could become so in the future;</li><li>a description of the most important risks and opportunities for the organization arising from sustainability trends;</li><li> prioritization of key economic, environmental, and social topics as risks and opportunities according to their relevance for long-term organizational strategy, competitive position, qualitative, and, if possible, quantitative financial value drivers;</li><li>table(s) summarizing targets, performance against targets, and lessons learned for the current reporting period;</li><li>table(s) summarizing targets for the next reporting period and medium-term objectives and goals (i.e., 3–5 years) related to key risks and opportunities;</li><li>a description of governance mechanisms in place specifically to manage these risks and opportunities, and identification of other related risks and opportunities. </li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r16-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in this disclosure, the reporting organization should provide additional information about its values, principles, standards, and norms of behavior, including: <ul><li> how they were developed and approved; </li><li> whether training on them is given regularly to all and new governance body members, workers performing the organization’s activities, and business partners;</li><li> whether they need to be read and signed regularly by all and new governance body members, workers performing the organization’s activities, and business partners; <li> whether any executive-level positions maintain responsibility for them;</li><li> whether they are available in different languages to reach all governance body members, workers performing the organization’s activities, business partners, and other stakeholders.</li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r17-REC", "NaN", "RECOMMENDATION", "Examples of elements that can be described include:<ul><li>Who is assigned the overall responsibility for the mechanisms to seek advice about and report on behavior;</li><li>Whether any mechanisms are independent of the organization;</li><li>Whether and how workers performing the organization’s activities, business partners, and other stakeholders are informed of the mechanisms;</li><li>Whether training on them is given to workers performing the organization’s activities and business partners;</li><li>The availability and accessibility of the mechanisms to workers performing the organization’s activities and business partners, such as the total number of hours per day, days per week, and availability in different languages;</li><li>Whether requests for advice and concerns are treated confidentially;</li><li>Whether the mechanisms can be used anonymously;</li><li>The total number of requests for advice received, their type, and the percentage that were answered during the reporting period;</li><li>The total number of concerns reported, the type of misconduct reported, and the percentage of concerns that were addressed, resolved, or found to be unsubstantiated during the reporting period;</li><li>Whether the organization has a non-retaliation policy;</li><li>The process through which concerns are investigated;</li><li>The level of satisfaction of those who used the mechanisms.</ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r38-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in Disclosure 102-38, the reporting organization shall, for each country of significant operations:<ul><li>identify the highest-paid individual for the reporting period, as defined by total compensation;</li><li>calculate the median annual total compensation for all employees, except the highestpaid individual;</li><li>calculate the ratio of the annual total compensation of the highest-paid individual to the median annual total compensation for all employees.</li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r39-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in Disclosure 102-39, the reporting organization shall, for each country of significant operations:<ul><li>identify the highest-paid individual for the reporting period, as defined by total compensation;</li><li>calculate the percentage increase in the highest-paid individual’s compensation from prior period to the reporting period;</li><li>calculate median annual total compensation for all employees except the highest-paid individual;</li><li>calculate the percentage increase of the median annual total compensation from the previous reporting period to the current reporting period;</li><li>calculate the ratio of the annual total compensation percentage increase of the highest-paid individual to the median annual total compensation percentage increase for all employees.</li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-102-r43-REC", "NaN", "RECOMMENDATION", "Methods of stakeholder engagement can include surveys (such as supplier, customer, or worker surveys), focus groups, community panels, corporate advisory panels, written communication, management or union structures, collective bargaining agreements, and other mechanisms. For many organizations, customers are a relevant stakeholder group. As well as measuring an organization’s sensitivity to its customers’ needs and preferences, customer satisfaction or dissatisfaction can give insight into the degree to which the organization considers the needs of stakeholders.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-103-r1-REC", "NaN", "RECOMMENDATION", "If an organization’s management approach or its components, such as policies or specific actions, apply to more than one material topic, the narrative description does not need to be repeated for each topic. Such information can be provided once in a report, with a clear explanation of the topics it covers.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-103-r2-REC", "NaN", "RECOMMENDATION", "<p>Material topics are those that reflect an organization’s significant economic, environmental and social impacts; or that substantively influence the assessments and decisions of stakeholders. The list of material topics is reported in Disclosure 102-47 of GRI 102: General Disclosures. For more information on identifying material topics, see GRI 101: Foundation. The explanation of why the topic is material can include: • a description of the significant impacts identified and the reasonable expectations and interests of stakeholders regarding the topic; • a description of the process, such as due diligence, that the organization used to identify the impacts related to the topic.</p><p>Organizations might be involved with impacts either through their own activities or as a result of their business relationships with other entities. An organization preparing a report in accordance with the GRI Standards is expected to report not only on impacts it causes, but also on impacts it contributes to, and impacts that are directly linked to its activities, products or services through a business relationship. In the context of this GRI Standard, an organization’s business relationships can include relationships with business partners, entities in its value chain, and any other non-State or State entity directly linked to its business operations, products or services.2 The topic Boundary is the description of where the impacts for a material topic occur, and the organization’s involvement with these impacts. When describing ‘where the impacts occur’, the organization can identify the entities where impacts occur, which can be entities in the organization,3 and/or entities with which it has a business relationship, such as entities in its value chain. The entities can be grouped based on their attributes, such as their type, location, or position in the value chain. Examples include ‘customers using washing machines manufactured by the organization’, ‘chemical suppliers in region X’, or ‘trading subsidiaries of the organization’.</p><p>In some cases, if the Boundary of a topic extends beyond the organization, it may not be possible to report some topic-specific disclosures. For example, if the Boundary for a topic includes part of the supply chain, the organization might not be able to access the necessary information from suppliers. In these cases, to prepare a report in accordance with the GRI Standards, the organization is still required to report its management approach for the topic, but can use the recognized reasons for omission for topic-specific disclosures.</p>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-201-r2-REC", "NaN", "RECOMMENDATION", "<p>Information on the creation and distribution of economic value provides a basic indication of how an organization has created wealth for stakeholders. Several components of the economic value generated and distributed (EVG&D) also provide an economic profile of an organization, which can be useful for normalizing other performance figures. If presented in country-level detail, EVG&D can provide  a useful picture of the direct monetary value added to local economies.</p>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-201-r3-REC", "NaN", "RECOMMENDATION", "<p>When compiling the information specified, if the reporting organization does not have a system in place to calculate the financial implications or costs, or to make revenue projections, it shall report its plans and timeline to develop the necessary systems.</p><pRisk and opportunities due to climate change can be classified as physical, regulatory and other. Physical risks and opportunities can include: the impact of more frequent and intense storms; changes in sea level, ambient temperature, and water availability; impacts on workers – such as health effects, including heat-related illness or disease, and the need to relocate operations.></p>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-201-r4-REC", "NaN", "RECOMMENDATION", "The structure of retirement plans offered to employees can be based on: <ul><li> defined benefit plans; </li><li> defined contribution plans; </li><li> other types of retirement benefits.</li></ul> Different jurisdictions, such as countries, have varying interpretations and guidance regarding calculations used to determine plan coverage. Note that benefit pension plans are part of the International Accounting Standards Board (IASB) IAS 19 Employee Benefits, however IAS 19 covers additional topics.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-201-r5-REC", "NaN", "RECOMMENDATION", "This disclosure provides a measure of governments’ contributions to an organization. The significant financial assistance received from a government, in comparison with taxes paid, can be useful for developing a balanced picture of the transactions between the organization and government.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-202-r2-REC", "NaN", "RECOMMENDATION", "This disclosure applies to those organizations in which a substantial portion of their employees, and workers (excluding employees) performing the organization’s activities, are compensated in a manner or scale that is closely linked to laws or regulations on minimum wage. Providing wages above the minimum wage can help contribute to the economic well-being of workers performing the organization’s activities. The impacts of wage levels are immediate, and they directly affect individuals, organizations, countries and economies. The distribution of wages is crucial for eliminating inequalities, such as wage gap differences between women and men, or nationals and migrants. Also, entry level wages paid compared to local minimum wages show the competitiveness of an organization’s wages and provide information relevant for assessing the effect of wages on the local labor market. Comparing this information by gender can also be a measure of an organization’s approach to equal opportunity in the workplace.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-202-r3-REC", "NaN", "RECOMMENDATION", "Senior management hired from the local community includes those individuals either born or who have the legal right to reside indefinitely (such as naturalized citizens or permanent visa holders) in the same geographic market as the operation. The geographical definition of ‘local’ can include the community surrounding operations, a region within a country, or a country. Including members from the local community in an organization’s senior management demonstrates the organization’s positive market presence. Including local community members in the management team can enhance human capital. It can also increase the economic benefit to the local community, and improve an organization’s ability to understand local needs.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-203-r1-REC", "NaN", "RECOMMENDATION", "The reporting organization should: describe work undertaken to understand indirect economic impacts at the national, regional, or local level; explain whether it conducted a community needs assessment to determine the need for infrastructure and other services, and describe the results of the assessment.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-203-r2-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in Disclosure 203-1, the reporting organization should disclose: the size, cost and duration of each significant infrastructure investment or service supported; the extent to which different communities or local economies are impacted by the organization’s infrastructure investments and services supported.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-203-r3-REC", "NaN", "RECOMMENDATION", "This disclosure concerns the spectrum of indirect economic impacts that an organization can have on its stakeholders and the economy. Examples of significant indirect economic impacts, both positive and negative, can include: <ul><li>changes in the productivity of organizations, sectors, or the whole economy (such as through greater adoption of information technology); </li><li>economic development in areas of high poverty (such as changes in the total number of dependents supported through the income of a single job); </li><li>economic impacts of improving or deteriorating social or environmental conditions (such as changing job market in an area converted from small farms to large plantations, or the economic impacts of pollution); </li><li>availability of products and services for those on low incomes (such as preferential pricing of pharmaceuticals, which contributes to a healthier population that can participate more fully in the economy; or pricing structures that exceed the economic capacity of those on low incomes); </li><li>enhanced skills and knowledge in a professional community or in a geographic location (such as when shifts in an organization’s needs attract additional skilled workers to an area, who, in turn, drive a local need for new learning institutions); </li><li>number of jobs supported in the supply or distribution chain (such as the employment impacts on suppliers as a result of an organization’s growth or contraction); </li><li>stimulating, enabling, or limiting foreign direct investment (such as when an organization changes the infrastructure or services it provides in a developing country, which then leads to changes in foreign direct investment in the region); </li><li>economic impacts from a change in operation or activity location (such as the impact of outsourcing jobs to an overseas location);economic impacts from the use of products and services (such as economic growth resulting from the use of a particular product or service).</li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-204-r1-REC", "NaN", "RECOMMENDATION", "When reporting its management approach for procurement practices, the reporting organization can also: describe actions taken to identify and adjust the organization’s procurement practices that cause or contribute to negative impacts in the supply chain, including: how dialogue with suppliers is used to identify procurement practices that cause or contribute to negative impacts in the supply chain; actions taken to adjust payment policies and procedures; describe policies and practices used to select locally-based suppliers, either organization-wide or for specific locations; explain the rationale and methodology for tracing the source, origin, or production conditions of raw materials and production inputs purchased, if applicable; describe policies and practices used to promote economic inclusion when selecting suppliers. Procurement practices that cause or contribute to negative impacts in the supply chain can include: stability or length of relationships with suppliers; lead times; ordering and payment routines; purchasing prices; changing or cancelling orders. Forms of economic inclusion can include: small and medium-sized suppliers; suppliers owned by women; suppliers which are owned by or recruit workers from members of vulnerable, marginalized, or under-represented social groups.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-204-r2-REC", "NaN", "RECOMMENDATION", "Local purchases can be made either from a budget managed at the location of operation or at an organization’s headquarters. By supporting local suppliers, an organization can indirectly attract additional investment to the local economy. Local sourcing can be a strategy to help ensure supply, support a stable local economy, and maintain community relations.", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-205-r2-REC", "NaN", "RECOMMENDATION", "<p>This disclosure can include a risk assessment focused on corruption or the inclusion of corruption as a risk factor in overall risk assessments.</p><p>The term ‘operation’ refers to a single location used by the organization for the production, storage and/or distribution of its goods and services, or for administrative purposes. Within a single operation, there can be multiple production lines, warehouses, or other activities. For example, a single factory can be used for multiple products or a single retail outlet can contain several different retail operations that are owned or managed by the organization.</p>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-301-r2-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in Disclosure 301-1, the reporting organization should: <ul><li>include the following material types in the calculation of total materials used: raw materials, i.e., natural resources used for conversion to products or services, such as ores, minerals, and wood; associated process materials, i.e., materials that are needed for the manufacturing process but are not part of the final product, such as lubricants for manufacturing machinery; semi-manufactured goods or parts, including all forms of materials and components other than raw materials that are part of the final product;  materials for packaging purposes, including paper, cardboard and plastics; </li><li>report, for each material type, whether it was purchased from external suppliers or sourced internally (such as by captive production and extraction activities); </li><li>report whether these data are estimated or sourced from direct measurements; </li><li>if estimation is required, report the methods used.</li></ul>", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-301-r3-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in Disclosure 301-2, the reporting organization shall: use the total weight or volume of materials used as specified in Disclosure 301-1; calculate the percentage of recycled input materials used by applying the following formula: Percentage of recycled input materials used = (Total recycled input materials used/Total input materials used) * 100", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-301-r4-REC", "NaN", "RECOMMENDATION", "When compiling the information specified in Disclosure 301-3, the reporting organization shall: exclude rejects and recalls of products; calculate the percentage of reclaimed products and their packaging materials for each product category using the following formula: Percentage of reclaimed products and their packaging materials = (Products and their packaging materialsreclaimed within the reporting period/Products sold within the reporting period) * 100", NOW(), NOW(), NOW());
INSERT INTO gri_vocabulary(Identifier, Quality, Metric, Description, Last_used, Last_updated, Time_created) VALUES ("GRI-302-r4-REC", "NaN", "RECOMMENDATION", "Intensity ratios can be provided for, among others: products (such as energy consumed per unit produced); services (such as energy consumed per function or per service); sales (such as energy consumed per monetary unit of sales). Organization-specific metrics (denominators) can include: units of product; production volume (such as metric tons, liters, or MWh); size (such as m2 floor space); number of full-time employees; monetary units (such as revenue or sales).", NOW(), NOW(), NOW());